<template>
	<view class="container">
		<scroll-view scroll-y class="form-container">
			<view class="form-section">
				<view class="form-label">纠纷来源 <text class="required">*</text></view>
				<picker mode="selector" :range="sourceOptions" :value="sourceIndex" @change="onSourceChange">
					<view class="picker-input">
						<text :class="{ placeholder: !formData.source }">{{ formData.source || '请选择纠纷来源' }}</text>
						<text class="arrow">›</text>
					</view>
				</picker>
			</view>
			
			<view class="form-section">
				<view class="form-label">纠纷标题 <text class="required">*</text></view>
				<input class="input" v-model="formData.title" placeholder="请输入纠纷标题" maxlength="100" />
			</view>
			
			<view class="form-section">
				<view class="form-label">纠纷描述 <text class="required">*</text></view>
				<textarea class="textarea" v-model="formData.description" placeholder="请详细描述纠纷情况" maxlength="500" />
			</view>
			
			<view class="form-section">
				<view class="form-label">发生位置 <text class="required">*</text></view>
				<view class="location-box" @click="chooseLocation">
					<view v-if="formData.location.address" class="location-info">
						<text class="location-text">{{ formData.location.address }}</text>
						<text class="location-btn">重新选择</text>
					</view>
					<view v-else class="location-placeholder">
						<text class="icon">📍</text>
						<text>点击选择位置</text>
					</view>
				</view>
				<map v-if="formData.location.latitude" 
					:latitude="formData.location.latitude" 
					:longitude="formData.location.longitude"
					:markers="markers"
					class="map-view"
					@tap="chooseLocation">
				</map>
			</view>
			
			<view class="form-section">
				<view class="form-label">涉及人员</view>
				<input class="input" v-model="formData.parties" placeholder="请输入涉及人员姓名" />
			</view>
			
			<view class="form-section">
				<view class="form-label">紧急度</view>
				<radio-group @change="onUrgencyChange">
					<label v-for="(item, index) in urgencyOptions" :key="index" class="radio-item">
						<radio :value="item" :checked="formData.urgency === item" />
						<text>{{ item }}</text>
					</label>
				</radio-group>
			</view>
			
			<view class="form-section">
				<view class="form-label">发生次数</view>
				<input class="input" type="number" v-model.number="formData.occur_count" placeholder="请输入发生次数" />
			</view>
			
			<view class="submit-section">
				<button class="btn-primary btn-submit" @click="submitForm" :loading="submitting">
					{{ submitting ? '提交中...' : '提交' }}
				</button>
			</view>
		</scroll-view>
	</view>
</template>

<script setup>
	import { ref, reactive } from 'vue'
	import { useUserStore } from '@/store/user'
	
	const userStore = useUserStore()
	
	const sourceOptions = ['接处警', '社区摸排', '工作发现']
	const urgencyOptions = ['一般', '紧急', '特急']
	const sourceIndex = ref(0)
	
	const formData = reactive({
		source: '',
		title: '',
		description: '',
		location: {
			address: '',
			latitude: null,
			longitude: null
		},
		parties: '',
		urgency: '一般',
		occur_count: 1
	})
	
	const markers = ref([])
	const submitting = ref(false)
	
	function onSourceChange(e) {
		const index = parseInt(e.detail.value)
		sourceIndex.value = index
		formData.source = sourceOptions[index]
	}
	
	function onUrgencyChange(e) {
		formData.urgency = e.detail.value
	}
	
	async function chooseLocation() {
		try {
			// 获取当前位置
			const locationRes = await uni.chooseLocation({
				success: (res) => {
					formData.location = {
						address: res.address,
						latitude: res.latitude,
						longitude: res.longitude
					}
					markers.value = [{
						id: 1,
						latitude: res.latitude,
						longitude: res.longitude,
						title: res.name
					}]
				},
				fail: (err) => {
					console.error('选择位置失败', err)
					uni.showToast({
						title: '选择位置失败',
						icon: 'none'
					})
				}
			})
		} catch (e) {
			console.error('获取位置失败', e)
			uni.showToast({
				title: '请授权位置权限',
				icon: 'none'
			})
		}
	}
	
	async function submitForm() {
		// 表单验证
		if (!formData.source) {
			uni.showToast({
				title: '请选择纠纷来源',
				icon: 'none'
			})
			return
		}
		
		if (!formData.title.trim()) {
			uni.showToast({
				title: '请输入纠纷标题',
				icon: 'none'
			})
			return
		}
		
		if (!formData.description.trim()) {
			uni.showToast({
				title: '请输入纠纷描述',
				icon: 'none'
			})
			return
		}
		
		if (!formData.location.address) {
			uni.showToast({
				title: '请选择发生位置',
				icon: 'none'
			})
			return
		}
		
		submitting.value = true
		
		try {
			const res = await uniCloud.callFunction({
				name: 'pushToStreet',
				data: {
					disputeData: formData,
					userInfo: {
						openid: userStore.openid,
						name: userStore.name
					}
				}
			})
			
			if (res.result.success) {
				uni.showToast({
					title: '提交成功',
					icon: 'success'
				})
				
				// 清空表单
				setTimeout(() => {
					formData.source = ''
					formData.title = ''
					formData.description = ''
					formData.location = { address: '', latitude: null, longitude: null }
					formData.parties = ''
					formData.urgency = '一般'
					formData.occur_count = 1
					markers.value = []
					sourceIndex.value = 0
					
					// 返回首页
					uni.switchTab({
						url: '/pages/index/index'
					})
				}, 1500)
			} else {
				throw new Error(res.result.error || '提交失败')
			}
		} catch (e) {
			console.error('提交失败', e)
			uni.showToast({
				title: e.message || '提交失败',
				icon: 'none'
			})
		} finally {
			submitting.value = false
		}
	}

	// 分享给朋友
	const onShareAppMessage = () => {
		return {
			title: '纠纷录入',
			path: '/pages/input/index',
			desc: '快速录入矛盾纠纷信息，及时处理社会问题',
			imageUrl: '/static/logo.png'
		}
	}

	defineExpose({
		onShareAppMessage
	})
</script>

